@function gcd($first-number, $second-number)

	@if meta.type-of($first-number) != 'number'
		// 'numbers' is used here as the parameter name, because the error is only intended for `@sass-fairy/math.gcd()`.
		@error parameter-type.parameter-type('gcd', 'numbers', $first-number, 'number')

	@if meta.type-of($second-number) != 'number'
		// 'numbers' is used here as the parameter name, because the error is only intended for `@sass-fairy/math.gcd()`.
		@error parameter-type.parameter-type('gcd', 'numbers', $second-number, 'number')

	$first-number: math.abs($first-number)
	$second-number: math.abs($second-number)

	@return if(sass($second-number == 0): $first-number; else: gcd($second-number, $first-number % $second-number))

@function index($string, $substring, $start-at: 1)

	@if meta.type-of($string) != 'string'
		@error parameter-type.parameter-type('index', 'string', $string, 'string')

	@if meta.type-of($substring) != 'string'
		@error parameter-type.parameter-type('index', 'substring', $substring, 'string')

	$start-at: validate-index.validate-index('index', 'start-at', $start-at, $string)

	@if meta.type-of($start-at) != 'number'
		@error $start-at

	$length: string.length($string)

	@if $start-at < $length * -1
		$start-at: 1

	$string: string.index(string.slice($string, $start-at), $substring)

	@return if(sass($string): $string + math.min($start-at, $length) - 1; else: 0)

@function ends-with($string, $substring, $end-at: -1)

	@if meta.type-of($string) != 'string'
		@error parameter-type.parameter-type('ends-with', 'string', $string, 'string')

	@if meta.type-of($substring) != 'string'
		@error parameter-type.parameter-type('ends-with', 'substring', $substring, 'string')

	$end-at: validate-index.validate-index('ends-with', 'end-at', $end-at, $string)

	@if meta.type-of($end-at) != 'number'
		@error $end-at

	$start-at: $end-at - string.length($substring) + 1

	@return index.index($string, $substring, $start-at) == $start-at

@function slice($list, $start-at, $end-at: -1, $separator: auto)
	$start-at: validate-index.validate-index('slice', 'start-at', $start-at, $list)

	@if meta.type-of($start-at) != 'number'
		@error $start-at

	$end-at: validate-index.validate-index('slice', 'end-at', $end-at, $list)

	@if meta.type-of($end-at) != 'number'
		@error $end-at

	@if $start-at > $end-at
		@error parameter.parameter('The starting index is not less than the ending index', 'slice', 'start-at', 'end-at')

	@if is-separator-invalid.is-separator-invalid($separator)
		@error separator.separator('slice')

	$result: empty.empty($separator, $list: $list)

	@for $i from $start-at through $end-at
		$result: list.append($result, list.nth($list, $i))

	@return $result

@function box-model($values, $side)
	$length: list.length($values)

	@if $length < 1 or $length > 4
		@error parameter.parameter('May not contain less than 1 item or more than 4 items', 'box-model', 'values')

	@if meta.type-of($side) != 'string'
		@error parameter-type.parameter-type('box-model', 'side', $side, 'string')

	@if $side != 'top' and $side != 'right' and $side != 'bottom' and $side != 'left'
		@error parameter.parameter('Must be "top", "right", "bottom", or "left"', 'box-model', 'side')

	@if $length == 1
		@return $values

	@return map.get((top: list.nth($values, 1), right: list.nth($values, 2), bottom: list.nth($values, if(sass($length > 2): 3; else: 1)), left: list.nth($values, if(sass($length == 4): 4; else: 2))), $side)

@function validate-index($context, $name, $value, $list)

	@if meta.type-of($value) != 'number'
		@return parameter-type.parameter-type($context, $name, $value, 'number')

	$is-list: meta.type-of($list) != 'string'

	@if $is-list and $value == 0
		@return parameter.parameter('List index may not be 0', $context, $name)

	$length: if(sass($is-list): list.length($list); else: string.length($list))
	$negative-transform: $value + $length + 1

	@if $value < 1 and ($negative-transform >= 1 and $negative-transform <= $length)
		$value: $negative-transform

	@if $is-list and ($value < 0 or $value > $length)
		@return parameter.parameter('Invalid index #{$value} for a list with #{$length} elements', $context, $name)

	@return $value

@function map-deep-merge($parent-map, $child-map)
  $result: $parent-map

  @each $key, $child in $child-map
    $parent-has-key: map.has-key($result, $key)
    $parent-value: map.get($result, $key)
    $parent-type: meta.type-of($parent-value)
    $child-type: meta.type-of($child)
    $parent-is-map: $parent-type == map
    $child-is-map: $child-type == map

    @if (not $parent-has-key) or ($parent-type != $child-type) or (not ($parent-is-map and $child-is-map))
      $result: map.merge($result, ( $key: $child ))

    @else
      $result: map.merge($result, ( $key: map-deep-merge($parent-value, $child) ))

  @return $result

@function divide($dividend, $divisor, $precision: 10)
  $sign: if($dividend > 0 and $divisor > 0, 1, -1)
  $dividend: abs($dividend)
  $divisor: abs($divisor)
  $quotient: 0
  $remainder: $dividend
  @if $dividend == 0
    @return 0
  @if $divisor == 0
    @error "Cannot divide by 0"
  @if $divisor == 1
    @return $dividend
  @while $remainder >= $divisor
    $quotient: $quotient + 1
    $remainder: $remainder - $divisor
  @if $remainder > 0 and $precision > 0
    $remainder: divide($remainder * 10, $divisor, $precision - 1) * .1
  @return ($quotient + $remainder) * $sign

@function validate-index($context, $name, $value, $list)

	@if meta.type-of($value) != 'number'
		@return parameter-type.parameter-type($context, $name, $value, 'number')

	$is-list: meta.type-of($list) != 'string'

	@if $is-list and $value == 0
		@return parameter.parameter('List index may not be 0', $context, $name)

	$length: if($is-list, list.length($list), string.length($list))
	$negative-transform: $value + $length + 1

	@if $value < 1 and ($negative-transform >= 1 and $negative-transform <= $length)
		$value: $negative-transform

	@if $is-list and ($value < 0 or $value > $length)
		@return parameter.parameter('Invalid index #{$value} for a list with #{$length} elements', $context, $name)

	@return $value

