@function index($string, $substring, $start-at: 1)

	@if meta.type-of($string) != 'string'
		@error parameter-type.parameter-type('index', 'string', $string, 'string')

	@if meta.type-of($substring) != 'string'
		@error parameter-type.parameter-type('index', 'substring', $substring, 'string')

	$start-at: validate-index.validate-index('index', 'start-at', $start-at, $string)

	@if meta.type-of($start-at) != 'number'
		@error $start-at

	$length: string.length($string)

	@if $start-at < $length * -1
		$start-at: 1

	$string: string.index(string.slice($string, $start-at), $substring)

	@return if($string, $string + math.min($start-at, $length) - 1, 0)

@function last-index($string, $substring, $end-at: -1)

	@if meta.type-of($string) != 'string'
		@error parameter-type.parameter-type('last-index', 'string', $string, 'string')

	@if meta.type-of($substring) != 'string'
		@error parameter-type.parameter-type('last-index', 'substring', $substring, 'string')

	$end-at: validate-index.validate-index('last-index', 'end-at', $end-at, $string)

	@if meta.type-of($end-at) != 'number'
		@error $end-at

	$string: string.slice($string, 1, $end-at)
	$result: index.index($string, $substring)
	$next-index: $result
	$length: string.length($string)

	@while $next-index > 0 and $next-index <= $length
		$result: $next-index
		$next-index: index.index($string, $substring, $result + 1)

	@return $result

@function replace($string, $substring, $replacement, $original)
	$index: string.index($string, $substring)

	@if $index
		$length: string.length($substring)
		$offset: $index + string.length($original) - string.length($string)
		$replace: $replacement

		@if string.index($replace, '$&') != null
			$replace: replace($replace, '$&', $substring, $replace)

		@if string.index($replace, '$`') != null
			$replace: replace($replace, '$`', string.slice($original, 1, $offset - 1), $replace)

		@if string.index($replace, "$'") != null
			$replace: replace($replace, "$'", string.slice($original, $offset + $length), $replace)

		@return string.slice($string, 1, $index - 1) + $replace + replace(string.slice($string, $index + $length), $substring, $replacement, $original)

	@return $string

@mixin active-states ($selector, $base: map.get(settings.$states, 'activated'))
  #{$selector}
    opacity: calc(#{$base} * var(--v-theme-overlay-multiplier))

  &:hover
    #{$selector}
      opacity: calc((#{$base} + #{map.get(settings.$states, 'hover')}) * var(--v-theme-overlay-multiplier))

  &:focus-visible
    #{$selector}
      opacity: calc((#{$base} + #{map.get(settings.$states, 'focus')}) * var(--v-theme-overlay-multiplier))

  @supports not selector(:focus-visible)
    &:focus
      #{$selector}
        opacity: calc((#{$base} + #{map.get(settings.$states, 'focus')}) * var(--v-theme-overlay-multiplier))

@function gcd($first-number, $second-number)

	@if meta.type-of($first-number) != 'number'
		// 'numbers' is used here as the parameter name, because the error is only intended for `@sass-fairy/math.gcd()`.
		@error parameter-type.parameter-type('gcd', 'numbers', $first-number, 'number')

	@if meta.type-of($second-number) != 'number'
		// 'numbers' is used here as the parameter name, because the error is only intended for `@sass-fairy/math.gcd()`.
		@error parameter-type.parameter-type('gcd', 'numbers', $second-number, 'number')

	$first-number: math.abs($first-number)
	$second-number: math.abs($second-number)

	@return if($second-number == 0, $first-number, gcd($second-number, $first-number % $second-number))

@function _numeric($first-item, $second-item, $center: 0)

	@if meta.type-of($first-item) != 'number'
		@return 1

	@if meta.type-of($second-item) != 'number'
		@return -1

	$center-test: math.is-unitless($center)
	$first-test: math.is-unitless($first-item)
	$second-test: math.is-unitless($second-item)

	// Normalize units for incompatible and unitless numbers
	@if $center-test and not $first-test or $first-test or not math.compatible($first-item, $center)
		$first-item: change.change($first-item, $center)

	@if $center-test and not $second-test or $second-test or not math.compatible($second-item, $center)
		$second-item: change.change($second-item, $center)

	@return $first-item - $second-item

=generate-utility-body($utility, $properties, $value, $infix)
  // Use custom class if present
  $property-class: map.get($utility, class)
  @if not $property-class
    $property-class: list.nth($properties, 1)

  // Don't prefix if value key is null (eg. with shadow class)
  $property-class-modifier: ''
  @if list.nth($value, 1)
    $property-class-modifier: '-' + list.nth($value, 1)

  $value: list.nth($value, 2)

  .#{$property-class + $infix + $property-class-modifier}
    @for $i from 1 through list.length($properties)
      $property: list.nth($properties, $i)
      $val: $value
      @if meta.type-of($value) == 'list' and list.length($properties) == list.length($value)
        $val: list.nth($value, $i)
      @if $val != false
        #{$property}: #{meta.inspect($val)}

@function trim-list($list, $start, $dir: 'asc')
  // built-in list trimming in Sass would make this go away.
  // declare some empty lists to put our trimmed values
  $trimmed: ()
  // if sorting ascending
  @if $dir == 'asc'
    // loop through all values in $list
    @for $i from 1 through length($list)
      @if nth($list, $i) >= $start
        $trimmed: append($trimmed, nth($list, $i))
  @if $dir == 'dec'
    // loop through all values in $list
    @for $i from 1 through length($list)
      @if nth($list, $i) <= $start
        $trimmed: append($trimmed, nth($list, $i))
  @return $trimmed

=grid-span($span, $location: $grid-counter, $columns: $columns, $gutter: $gutter, $padding: $padding)
  +box-sizing(border-box)
  width: grid-span($span, $location, $columns, $gutter)

  @if $grid-structure == float
    +structure-float($span, $location, $columns, $gutter)

  // add special left padding
  @if type-of($columns) == list
    @if type-of(nth($columns, $location)) == list
      padding-left: nth(nth($columns, $location), 2)
    @else if $padding != 0
      padding-left: $padding
    // add special right padding
    @if type-of(nth($columns, ($location + $span - 1))) == list
      padding-right: nth(nth($columns, ($location + $span - 1)), 2)
    @else if $padding != 0
      padding-right: $padding

  @else if $padding != 0
    padding: 0 $padding

  // bump up the counter
  $grid-counter: $location + $span
  @if $grid-counter > column-count($columns)
    $grid-counter: 1

=grid-objects($prefix: a, $columns: $columns, $gutter: $gutter, $padding: $padding, $selector: "%")

  $grouped-styles: true

  // counter keeps track of the starting position
  $count: 0
  %#{$prefix}column
    @if $dir == ltr or $dir == both
      margin-right: -100%
      float: left
    @if $dir == rtl
      margin-left: -100%
      float: right
    @if $dir == both
      #{$rtl-selector} &
        margin-left: -100%
        float: right
    float: left
    +grid-padding($padding)
    margin-right: $gutter

  @for $i from 1 through column-count($columns)
    @for $n from $count + 1 through column-count($columns)
      #{$selector}#{$prefix}#{$count}-#{$n}
        @extend %#{$prefix}column
        +grid-span($n - $count, $count + 1, $columns, $gutter)
    $count: $count + 1

=grid-span($span, $location: $grid-counter, $columns: $columns, $gutter: $gutter, $padding: $padding)
  +box-sizing(border-box)
  width: grid-span($span, $location, $columns, $gutter)

