    $grid-counter: 1

@function _string($first-item, $second-item, $center: never)

	@if $first-item == null
		@return 1

	@if $second-item == null
		@return -1

	$first-item: '"#{$first-item}"'
	$second-item: '"#{$second-item}"'

	@for $i from 1 through math.min(string.length($first-item), string.length($second-item))
		$first-index: list.index($_order, string.slice($first-item, $i, $i))
		$second-index: list.index($_order, string.slice($second-item, $i, $i))

		// The first item is not within the support UTF-16 range.
		@if not $first-index
			@return 1

		// The second item is not within the support UTF-16 range.
		@if not $second-index
			@return -1

		// Both items are found in the range, return the difference of the indexes of the characters.
		@if $first-index != $second-index
			@return $first-index - $second-index

	// Both items are equal
	@return 0

@function -find-value-($condition, $operator)
  $value: string.trim(string.slice($condition, map.get($operator, index) + map.get($operator, length)))

  @if map.has-key($breakpoints, $value)
    $value: map.get($breakpoints, $value)
  @else
    $parsed: number.parse($value)
    $value: if($parsed, $parsed, $value)

  @if meta.is-number($value)
    $unit: math.unit($value)
    $offset: if(map.has-key($unit-offset, $unit), map.get($unit-offset, $unit), 1)

    @if map.get($operator, symbol) == $-operator-gt-
      $value: $value + $offset
    @else if map.get($operator, symbol) == $-operator-lt-
      $value: $value - $offset
  @return $value

@function prefix($prefix, $property1, $property2: null, $property3: null, $property4: null, $property5: null, $property6: null, $property7: null, $property8: null, $property9: null)
  $properties: ""
  // Support for polymorphism.
  @if type-of($property1) == "list"
    // Passing a single array of properties.
    $properties: $property1
  @else
    // Passing multiple properties.
    $properties: $property1, $property2, $property3, $property4, $property5, $property6, $property7, $property8, $property9
  $props: false
  @each $item in $properties
    @if $item == null
    @else
      @if prefixed($prefix, $item)
        $item: #{$prefix}-#{$item}
      @if $props
        $props: $props, $item
      @else
        $props: $item
  @return $props
